import { CATALOG_EN } from "./catalog-en.mjs";
import { RULES } from "./rules-content.mjs";

const weapon = (slug, name, primary, alternate, range, sourcePage, description) => ({
  slug,
  kind: "weapon",
  name,
  primary,
  alternate,
  parameters: [primary, alternate],
  range,
  sourcePage,
  description
});

const weaponFeature = (slug, subtype, weaponSlug, name, sourcePage, description) => ({
  slug,
  kind: subtype === "trait" ? "trait" : "gimmick",
  subtype,
  weapon: weaponSlug,
  name,
  sourcePage,
  description
});

const ability = (
  slug,
  weaponSlug,
  name,
  level,
  category,
  sourcePage,
  description,
  { activation = category === "passive" ? "passive" : "action", requires = [] } = {}
) => ({
  slug,
  kind: "ability",
  weapon: weaponSlug,
  name,
  level,
  category,
  activation,
  requires,
  sourcePage,
  description
});

const spell = (
  slug,
  name,
  level,
  category,
  sourcePage,
  description,
  { activation = "action", requires = [], duration = "1 ход", area = "" } = {}
) => ({
  slug,
  kind: "spell",
  name,
  level,
  category,
  activation,
  requires,
  duration,
  area,
  sourcePage,
  description
});

const entry = (slug, kind, name, sourcePage, description, extra = {}) => ({
  slug,
  kind,
  name,
  sourcePage,
  description,
  ...extra
});

