function deepFreeze(value) {
  if (!value || typeof value !== "object" || Object.isFrozen(value)) return value;
  for (const child of Object.values(value)) deepFreeze(child);
  return Object.freeze(value);
}

export const CATALOG = deepFreeze({
  rules: RULES,
  weapons: WEAPONS,
  gimmicks: GIMMICKS,
  abilities: ABILITIES,
  spells: SPELLS,
  enemyTraits: ENEMY_TRAITS,
  statuses: STATUSES,
  maneuvers: MANEUVERS,
  tables: TABLES
});

function *allCatalogEntries(catalog) {
  for (const group of Object.values(catalog)) {
    for (const catalogEntry of group) {
      yield catalogEntry;
      if (catalogEntry.kind === "table") yield *catalogEntry.results;
    }
  }
}

export const CATALOG_INDEX = new Map();

for (const catalogEntry of allCatalogEntries(CATALOG)) {
  if (!/^[a-z0-9]+(?:-[a-z0-9]+)*$/.test(catalogEntry.slug)) {
    throw new Error(`Invalid catalog slug "${catalogEntry.slug}"; slugs must contain only lowercase ASCII letters, digits, and hyphens.`);
  }
  if (CATALOG_INDEX.has(catalogEntry.slug)) {
    throw new Error(`Duplicate catalog slug "${catalogEntry.slug}".`);
  }
  CATALOG_INDEX.set(catalogEntry.slug, catalogEntry);
}

export function getCatalogEntry(slug) {
  return localizeCatalogEntry(CATALOG_INDEX.get(slug));
}

function catalogLanguage(language = globalThis.game?.i18n?.lang) {
  return String(language ?? "ru").toLocaleLowerCase().startsWith("en") ? "en" : "ru";
}

export function localizeCatalogEntry(catalogEntry, language) {
  if (!catalogEntry || catalogLanguage(language) !== "en") return catalogEntry;
  const translation = catalogEntry.translations?.en ?? CATALOG_EN[catalogEntry.slug];
  const results = catalogEntry.results?.map((result) => localizeCatalogEntry(result, "en"));
  if (!translation && !results) return catalogEntry;
  return deepFreeze({
    ...catalogEntry,
    ...translation,
    ...(results ? { results } : {}),
    translations: undefined
  });
}

export function localizeCatalog(catalog = CATALOG, language) {
  if (catalogLanguage(language) !== "en") return catalog;
  return deepFreeze(Object.fromEntries(
    Object.entries(catalog).map(([group, entries]) => [
      group,
      entries.map((catalogEntry) => localizeCatalogEntry(catalogEntry, "en"))
    ])
  ));
}

const WEAPON_NAME_TO_SLUG = new Map(
  WEAPONS.flatMap((catalogWeapon) => {
    const english = CATALOG_EN[catalogWeapon.slug]?.name;
    return [catalogWeapon.name, english]
      .filter(Boolean)
      .map((name) => [name.toLocaleLowerCase(), catalogWeapon.slug]);
  })
);

function weaponSlugFrom(value) {
  if (!value) return null;
  if (typeof value === "string") {
    if (CATALOG_INDEX.get(value)?.kind === "weapon") return value;
    return WEAPON_NAME_TO_SLUG.get(value.trim().toLocaleLowerCase("ru-RU")) ?? null;
  }
  return weaponSlugFrom(value.slug)
    ?? weaponSlugFrom(value.system?.slug)
    ?? weaponSlugFrom(value.name);
}

function actorWeaponSlugs(actor) {
  const system = actor?.system ?? actor ?? {};
  const candidates = [
    system.weapon,
    system.weapons?.main,
    system.weapons?.reserve,
    system.mainWeapon,
    system.reserveWeapon
  ];

  if (actor?.items && Symbol.iterator in Object(actor.items)) {
    for (const item of actor.items) {
      if (item?.type === "weapon") candidates.push(item);
    }
  }

  return new Set(candidates.map(weaponSlugFrom).filter(Boolean));
}

export function catalogForActor(actor) {
  const selectedWeapons = actorWeaponSlugs(actor);
  if (selectedWeapons.size === 0) return localizeCatalog(CATALOG);

  return localizeCatalog(deepFreeze({
    rules: CATALOG.rules,
    weapons: CATALOG.weapons,
    gimmicks: CATALOG.gimmicks.filter((catalogEntry) => selectedWeapons.has(catalogEntry.weapon)),
    abilities: CATALOG.abilities.filter((catalogEntry) => selectedWeapons.has(catalogEntry.weapon)),
    spells: CATALOG.spells,
    enemyTraits: CATALOG.enemyTraits,
    statuses: CATALOG.statuses,
    maneuvers: CATALOG.maneuvers,
    tables: CATALOG.tables
  }));
}
